// Define a function to validate the HTML anchor tags
function validateAnchorTags(s) {
  // Initialize an empty stack to keep track of opening tags
  let stack = [];
  // Iterate over the input string
  for (let i = 0; i < s.length; i++) {
    // Check if the current character is the start of a tag
    if (s[i] === '<') {
      // Check if the tag is a closing tag
      if (s[i + 1] === '/') {
        // Check if the stack is not empty
        if (stack.length > 0) {
          // Get the top element from the stack
          let top = stack.pop();
          // Check if the closing tag matches the opening tag
          if (top !== s.substring(i + 2, s.indexOf('>', i))) {
            return false;
          }
        } else {
          return false;
        }
      } else {
        // Check if the tag is an anchor tag
        if (!['a', 'area', 'link'].includes(s.substring(i + 1, s.indexOf('>', i)))) {
          return false;
        }
        // Push the opening tag onto the stack
        stack.push(s.substring(i + 1, s.indexOf('>', i)));
      }
    }
  }
  // Check if the stack is empty
  if (stack.length > 0) {
    return false;
  }
  return true;
};

