class Solution:
    def validateAnchorTags(self, s: str) -> bool:
        stack = []
        for i in range(len(s)):
            if s[i] == '<':
                if s[i + 1] == '/':
                    if not stack:
                        return False
                    top = stack.pop()
                    if top != s.substring(i + 2, s.index('>', i)):
                        return False
                else:
                    if not any(tag in s[i + 1:s.index('>', i)] for tag in ['a', 'area', 'link']):
                        return False
                    stack.append(s[i + 1:s.index('>', i)])
        return not bool(stack)

